import React, { useState, useEffect } from 'react';
import { Corrida, RelacionamentoMotoristaIdoso } from "../interfaces/Corrida";
import axios from 'axios';

const estados = [
    { id: 12, sigla: "AC", nome: "Acre" },
    { id: 27, sigla: "AL", nome: "Alagoas" },
    { id: 16, sigla: "AP", nome: "Amapá" },
    { id: 13, sigla: "AM", nome: "Amazonas" },
    { id: 29, sigla: "BA", nome: "Bahia" },
    { id: 23, sigla: "CE", nome: "Ceará" },
    { id: 53, sigla: "DF", nome: "Distrito Federal" },
    { id: 32, sigla: "ES", nome: "Espírito Santo" },
    { id: 52, sigla: "GO", nome: "Goiás" },
    { id: 21, sigla: "MA", nome: "Maranhão" },
    { id: 51, sigla: "MT", nome: "Mato Grosso" },
    { id: 50, sigla: "MS", nome: "Mato Grosso do Sul" },
    { id: 31, sigla: "MG", nome: "Minas Gerais" },
    { id: 15, sigla: "PA", nome: "Pará" },
    { id: 25, sigla: "PB", nome: "Paraíba" },
    { id: 41, sigla: "PR", nome: "Paraná" },
    { id: 26, sigla: "PE", nome: "Pernambuco" },
    { id: 22, sigla: "PI", nome: "Piauí" },
    { id: 33, sigla: "RJ", nome: "Rio de Janeiro" },
    { id: 24, sigla: "RN", nome: "Rio Grande do Norte" },
    { id: 43, sigla: "RS", nome: "Rio Grande do Sul" },
    { id: 11, sigla: "RO", nome: "Rondônia" },
    { id: 14, sigla: "RR", nome: "Roraima" },
    { id: 42, sigla: "SC", nome: "Santa Catarina" },
    { id: 35, sigla: "SP", nome: "São Paulo" },
    { id: 28, sigla: "SE", nome: "Sergipe" },
    { id: 17, sigla: "TO", nome: "Tocantins" },
];

const fetchCidades = async (uf: string) => {
    const url = `https://servicodados.ibge.gov.br/api/v1/localidades/estados/${uf}/municipios?orderBy=nome`;
    const response = await fetch(url);
    const data = await response.json();
    return data.map((cidade: { id: number; nome: string }) => ({
        id: cidade.id,
        nome: cidade.nome,
    }));
};

const formatEndereco = (logradouro?: string, numero?: string, cidade?: string) => {
    const partes = [logradouro, numero, cidade].filter(Boolean);
    return partes.length ? partes.join(", ") : "-";
};

const statusBadgeClass = (status?: string) => {
    switch (status) {
        case "SOLICITADA":
            return "badge text-bg-warning";
        case "ACEITA":
        case "EM_ANDAMENTO":
            return "badge text-bg-success";
        case "FINALIZADA":
            return "badge text-bg-primary";
        case "CANCELADA":
            return "badge text-bg-danger";
        default:
            return "badge text-bg-secondary";
    }
};

const statusLabel = (status?: string) => {
    if (status === "EM_ANDAMENTO") {
        return "EM ANDAMENTO";
    }
    return status || "-";
};

function ListarTodosCorridas() {
    const [listaCorridas, setCorridas] = useState<Corrida[]>([]);
    const [relacionamentos, setRelacionamentos] = useState<RelacionamentoMotoristaIdoso[]>([]);
    const [loading, setLoading] = useState(true);
    const [msg, setMsg] = useState<string | null>(null);
    const [mostrarEditar, setMostrarEditar] = useState(false);
    const [editarCorrida, setEditarCorrida] = useState<any>(null);
    const [salvandoEdicao, setSalvandoEdicao] = useState(false);
    const [msgEdicao, setMsgEdicao] = useState<string | null>(null);
    const [carregandoEdicao, setCarregandoEdicao] = useState(false);
    const [editOrigemEstado, setEditOrigemEstado] = useState("");
    const [editDestinoEstado, setEditDestinoEstado] = useState("");
    const [editOrigemCidades, setEditOrigemCidades] = useState<{ id: number; nome: string }[]>([]);
    const [editDestinoCidades, setEditDestinoCidades] = useState<{ id: number; nome: string }[]>([]);
    const mostrarCarregando = loading || carregandoEdicao || salvandoEdicao;

    const carregarCorridas = () => {
        setLoading(true);
        const urlCorridas = "http://localhost:8080/corridas/todasCorridas";
        const urlRelacionamentos = "http://localhost:8080/relacionamentos";

        Promise.all([
            axios.get(urlCorridas),
            axios.get(urlRelacionamentos),
        ])
            .then(([resCorridas, resRelacionamentos]) => {
                setCorridas(resCorridas.data || []);
                setRelacionamentos(resRelacionamentos.data || []);
            })
            .catch((error) => {
                console.error("Erro ao buscar os itens:", error);
                setMsg("Erro ao carregar dados.");
            })
            .finally(() => setLoading(false));
    };

    /** Retorna o relacionamento motorista-idoso correspondente à corrida, se existir. */
    const relacionamentoDaCorrida = (corrida: Corrida): RelacionamentoMotoristaIdoso | undefined =>
        relacionamentos.find(
            (r) =>
                r.motorista?.id === corrida.motorista?.id && r.idoso?.id === corrida.idoso?.id
        );

    useEffect(() => {
        carregarCorridas();
    }, []);

    useEffect(() => {
        if (!editOrigemEstado) {
            setEditOrigemCidades([]);
            return;
        }
        fetchCidades(editOrigemEstado)
            .then((cidades) => {
                setEditOrigemCidades(cidades);
            })
            .catch(() => {
                setEditOrigemCidades([]);
            });
    }, [editOrigemEstado]);

    useEffect(() => {
        if (!editDestinoEstado) {
            setEditDestinoCidades([]);
            return;
        }
        fetchCidades(editDestinoEstado)
            .then((cidades) => {
                setEditDestinoCidades(cidades);
            })
            .catch(() => {
                setEditDestinoCidades([]);
            });
    }, [editDestinoEstado]);

    if (loading) {
        return <div className="loading-footer">Carregando</div>;
    }

    const handleDelete = (id) => {
        setLoading(true);
        fetch("http://localhost:8080/corridas/deletarCorrida/" + id, {
            method: 'DELETE',
        })
            .then((response) => {
                if (!response.ok && response.status === 404) {
                    setMsg('Corrida não encontrada.');
                    throw new Error('Erro ao excluir o curso.');
                }
                carregarCorridas();
            })
            .catch((error) => {
                if (error.status === 404) {
                    setMsg('Corrida não encontrada.');
                }
                console.error('Erro ao excluir o curso:', error);
                setLoading(false);
            });
    };

    const handleFinalizar = (id) => {
        setLoading(true);
        fetch(`http://localhost:8080/corridas/editarCorrida/${id}`, {
            method: "PUT",
            headers: {
                "Content-Type": "application/json",
            },
            body: JSON.stringify({ statusCorrida: "FINALIZADA" }),
        })
            .then((response) => {
                if (!response.ok) {
                    throw new Error("Erro ao finalizar corrida.");
                }
                carregarCorridas();
            })
            .catch(() => {
                setMsg("Erro ao finalizar corrida.");
                setLoading(false);
            });
    };

    const handleIniciar = (id, statusDestino) => {
        setLoading(true);
        fetch(`http://localhost:8080/corridas/editarCorrida/${id}`, {
            method: "PUT",
            headers: {
                "Content-Type": "application/json",
            },
            body: JSON.stringify({ statusCorrida: statusDestino }),
        })
            .then((response) => {
                if (!response.ok) {
                    throw new Error("Erro ao iniciar corrida.");
                }
                carregarCorridas();
            })
            .catch(() => {
                setMsg("Erro ao iniciar corrida.");
                setLoading(false);
            });
    };

    const handleCancelar = (id) => {
        setLoading(true);
        fetch(`http://localhost:8080/corridas/editarCorrida/${id}`, {
            method: "PUT",
            headers: {
                "Content-Type": "application/json",
            },
            body: JSON.stringify({ statusCorrida: "CANCELADA" }),
        })
            .then((response) => {
                if (!response.ok) {
                    throw new Error("Erro ao cancelar corrida.");
                }
                carregarCorridas();
            })
            .catch(() => {
                setMsg("Erro ao cancelar corrida.");
                setLoading(false);
            });
    };

    const abrirEditar = (corrida: Corrida) => {
        setCarregandoEdicao(true);
        const copia = JSON.parse(JSON.stringify(corrida));
        setEditarCorrida(copia);
        setEditOrigemEstado(copia?.origem?.estado || "");
        setEditDestinoEstado(copia?.destino?.estado || "");
        setMsgEdicao(null);
        setMostrarEditar(true);
        setTimeout(() => setCarregandoEdicao(false), 0);
    };

    const fecharEditar = () => {
        setMostrarEditar(false);
        setEditarCorrida(null);
        setMsgEdicao(null);
        setCarregandoEdicao(false);
        setEditOrigemEstado("");
        setEditDestinoEstado("");
        setEditOrigemCidades([]);
        setEditDestinoCidades([]);
    };

    const salvarEdicao = async () => {
        if (!editarCorrida?.id) {
            return;
        }
        setSalvandoEdicao(true);
        setCarregandoEdicao(true);
        setMsgEdicao(null);
        try {
            const response = await fetch(`http://localhost:8080/corridas/editarCorrida/${editarCorrida.id}`, {
                method: "PUT",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify(editarCorrida),
            });
            if (!response.ok) {
                const texto = await response.text();
                setMsgEdicao(texto || "Erro ao salvar edição.");
                return;
            }
            await response.json();
            setMostrarEditar(false);
            carregarCorridas();
        } catch (error) {
            setMsgEdicao("Erro ao salvar edição.");
        } finally {
            setSalvandoEdicao(false);
            setCarregandoEdicao(false);
        }
    };

    return (
        <>
            <div className="container" style={{marginTop: "80px", marginBottom: "20px"}}>
                <h2 className="mb-4" style={{textAlign: "center"}}>Lista de Corridas</h2>

                {msg && <div className="alert alert-info">{msg}</div>}

                <div className="card p-4 shadow-sm">
                    <div className="table-responsive">
                        <table className="table table-striped table-bordered">
                        <thead className="table-dark">
                        <tr>
                            <th>ID</th>
                            <th>Idoso</th>
                            <th>Motorista</th>
                            <th>Relacionamento (ID)</th>
                            <th>Origem</th>
                            <th>Destino</th>
                            <th>Status</th>
                            <th>Data/Hora</th>
                            <th>Ação</th>
                        </tr>
                        </thead>
                        <tbody>
                        {listaCorridas.map((item) => (
                            <tr key={item.id}>
                                <td>{item.id}</td>
                                <td>{item.idoso?.nome || "-"}</td>
                                <td>{item.motorista?.nome || "-"}</td>
                                <td>{formatEndereco(item.origem?.logradouro, item.origem?.numero, item.origem?.cidade)}</td>
                                <td>{formatEndereco(item.destino?.logradouro, item.destino?.numero, item.destino?.cidade)}</td>
                                <td>
                                    <div className="d-flex flex-column align-items-start gap-1">
                                        <div className="d-flex flex-column gap-2 w-100">
                                            {item.statusCorrida === "EM_ANDAMENTO" && (
                                                <button
                                                    onClick={() => handleFinalizar(item.id)}
                                                    className="btn btn-sm btn-outline-success w-100 py-1"
                                                    title="Finalizar corrida"
                                                >
                                                    Finalizar
                                                </button>
                                            )}
                                    {item.statusCorrida === "SOLICITADA" && (
                                                <button
                                            onClick={() => handleIniciar(item.id, "ACEITA")}
                                            className="btn btn-sm btn-outline-warning text-dark w-100 py-1"
                                                    title="Iniciar corrida"
                                                >
                                                    Iniciar
                                                </button>
                                            )}
                                    {item.statusCorrida === "ACEITA" && (
                                        <button
                                            onClick={() => handleIniciar(item.id, "EM_ANDAMENTO")}
                                            className="btn btn-sm btn-outline-success w-100 py-1"
                                            title="Iniciar corrida"
                                        >
                                            Iniciar
                                        </button>
                                    )}
                                        </div>
                                        <span className={`${statusBadgeClass(item.statusCorrida)} w-100 text-center`}>
                                            {statusLabel(item.statusCorrida)}
                                        </span>
                                    </div>
                                </td>
                                <td>{item.dataHoraSolicitacao}</td>
                            <td className="d-flex gap-2">
                                <button
                                    onClick={() => handleCancelar(item.id)}
                                    className="btn btn-sm btn-outline-danger"
                                    title="Cancelar corrida"
                                >
                                    Cancelar
                                </button>
                                <button
                                    onClick={() => abrirEditar(item)}
                                    className="btn btn-sm btn-outline-primary"
                                    title="Editar corrida"
                                >
                                    Editar
                                </button>
                                <button
                                    onClick={() => handleDelete(item.id)}
                                    className="btn btn-sm btn-outline-danger"
                                    title="Excluir corrida"
                                >
                                    X
                                </button>
                            </td>
                            </tr>
                        ))}
                        </tbody>
                        </table>
                    </div>
                </div>
            </div>
            {mostrarEditar && editarCorrida && (
            <div
                className="modal fade show"
                style={{display: "block", backgroundColor: "rgba(0,0,0,0.5)"}}
                role="dialog"
                aria-modal="true"
            >
                <div className="modal-dialog modal-lg modal-dialog-centered" role="document">
                    <div className="modal-content">
                        <div className="modal-header">
                            <h5 className="modal-title">Editar Corrida</h5>
                            <button
                                type="button"
                                className="btn-close"
                                aria-label="Fechar"
                                onClick={fecharEditar}
                            ></button>
                        </div>
                        <div className="modal-body">
                            {msgEdicao && <div className="alert alert-danger">{msgEdicao}</div>}
                            {carregandoEdicao || salvandoEdicao ? (
                                <p>Carregando...</p>
                            ) : (
                            <div className="row">
                                <div className="col-md-6">
                                    <div className="mb-3">
                                        <label className="form-label">Idoso - Nome</label>
                                        <input
                                            type="text"
                                            className="form-control"
                                            value={editarCorrida.idoso?.nome || ""}
                                            onChange={(e) =>
                                                setEditarCorrida((prev) =>
                                                    prev
                                                        ? { ...prev, idoso: { ...(prev.idoso || {}), nome: e.target.value } }
                                                        : prev
                                                )
                                            }
                                        />
                                    </div>
                                    <div className="mb-3">
                                        <label className="form-label">Motorista - Nome</label>
                                        <input
                                            type="text"
                                            className="form-control"
                                            value={editarCorrida.motorista?.nome || ""}
                                            onChange={(e) =>
                                                setEditarCorrida((prev) =>
                                                    prev
                                                        ? { ...prev, motorista: { ...(prev.motorista || {}), nome: e.target.value } }
                                                        : prev
                                                )
                                            }
                                        />
                                    </div>
                                    <div className="mb-3">
                                        <label className="form-label">Status</label>
                                        <select
                                            className="form-select"
                                            value={editarCorrida.statusCorrida || "SOLICITADA"}
                                            onChange={(e) =>
                                                setEditarCorrida((prev) =>
                                                    prev ? { ...prev, statusCorrida: e.target.value } : prev
                                                )
                                            }
                                        >
                                            <option value="SOLICITADA">SOLICITADA</option>
                                            <option value="ACEITA">ACEITA</option>
                                            <option value="EM_ANDAMENTO">EM ANDAMENTO</option>
                                            <option value="FINALIZADA">FINALIZADA</option>
                                            <option value="CANCELADA">CANCELADA</option>
                                        </select>
                                    </div>
                                    <div className="mb-3">
                                        <label className="form-label">Data/Hora</label>
                                        <input
                                            type="datetime-local"
                                            className="form-control"
                                            value={editarCorrida.dataHoraSolicitacao || ""}
                                            onChange={(e) =>
                                                setEditarCorrida((prev) =>
                                                    prev ? { ...prev, dataHoraSolicitacao: e.target.value } : prev
                                                )
                                            }
                                        />
                                    </div>
                                </div>
                                <div className="col-md-6">
                                    <div className="mb-3">
                                        <label className="form-label">Origem - Logradouro</label>
                                        <input
                                            type="text"
                                            className="form-control"
                                            value={editarCorrida.origem?.logradouro || ""}
                                            onChange={(e) =>
                                                setEditarCorrida((prev) =>
                                                    prev
                                                        ? { ...prev, origem: { ...(prev.origem || {}), logradouro: e.target.value } }
                                                        : prev
                                                )
                                            }
                                        />
                                    </div>
                                    <div className="mb-3">
                                        <label className="form-label">Origem - Número</label>
                                        <input
                                            type="text"
                                            className="form-control"
                                            value={editarCorrida.origem?.numero || ""}
                                            onChange={(e) =>
                                                setEditarCorrida((prev) =>
                                                    prev
                                                        ? { ...prev, origem: { ...(prev.origem || {}), numero: e.target.value } }
                                                        : prev
                                                )
                                            }
                                        />
                                    </div>
                                    <div className="mb-3">
                                        <label className="form-label">Origem - Estado</label>
                                        <select
                                            className="form-select"
                                            value={editOrigemEstado}
                                            onChange={(e) => {
                                                const valor = e.target.value;
                                                setEditOrigemEstado(valor);
                                                setEditarCorrida((prev) =>
                                                    prev
                                                        ? { ...prev, origem: { ...(prev.origem || {}), estado: valor, cidade: "" } }
                                                        : prev
                                                );
                                            }}
                                        >
                                            <option value="">Selecione o estado</option>
                                            {estados.map((estado) => (
                                                <option key={estado.sigla} value={estado.sigla}>
                                                    {estado.nome}
                                                </option>
                                            ))}
                                        </select>
                                    </div>
                                    <div className="mb-3">
                                        <label className="form-label">Origem - Cidade</label>
                                        <select
                                            className="form-select"
                                            value={editarCorrida.origem?.cidade || ""}
                                            onChange={(e) =>
                                                setEditarCorrida((prev) =>
                                                    prev
                                                        ? { ...prev, origem: { ...(prev.origem || {}), cidade: e.target.value } }
                                                        : prev
                                                )
                                            }
                                            disabled={!editOrigemEstado}
                                        >
                                            <option value="">
                                                {editOrigemEstado ? "Selecione a cidade" : "Selecione o estado"}
                                            </option>
                                            {editOrigemCidades.map((cidade) => (
                                                <option key={cidade.id} value={cidade.nome}>
                                                    {cidade.nome}
                                                </option>
                                            ))}
                                        </select>
                                    </div>
                                    <div className="mb-3">
                                        <label className="form-label">Destino - Logradouro</label>
                                        <input
                                            type="text"
                                            className="form-control"
                                            value={editarCorrida.destino?.logradouro || ""}
                                            onChange={(e) =>
                                                setEditarCorrida((prev) =>
                                                    prev
                                                        ? { ...prev, destino: { ...(prev.destino || {}), logradouro: e.target.value } }
                                                        : prev
                                                )
                                            }
                                        />
                                    </div>
                                    <div className="mb-3">
                                        <label className="form-label">Destino - Número</label>
                                        <input
                                            type="text"
                                            className="form-control"
                                            value={editarCorrida.destino?.numero || ""}
                                            onChange={(e) =>
                                                setEditarCorrida((prev) =>
                                                    prev
                                                        ? { ...prev, destino: { ...(prev.destino || {}), numero: e.target.value } }
                                                        : prev
                                                )
                                            }
                                        />
                                    </div>
                                    <div className="mb-3">
                                        <label className="form-label">Destino - Estado</label>
                                        <select
                                            className="form-select"
                                            value={editDestinoEstado}
                                            onChange={(e) => {
                                                const valor = e.target.value;
                                                setEditDestinoEstado(valor);
                                                setEditarCorrida((prev) =>
                                                    prev
                                                        ? { ...prev, destino: { ...(prev.destino || {}), estado: valor, cidade: "" } }
                                                        : prev
                                                );
                                            }}
                                        >
                                            <option value="">Selecione o estado</option>
                                            {estados.map((estado) => (
                                                <option key={estado.sigla} value={estado.sigla}>
                                                    {estado.nome}
                                                </option>
                                            ))}
                                        </select>
                                    </div>
                                    <div className="mb-3">
                                        <label className="form-label">Destino - Cidade</label>
                                        <select
                                            className="form-select"
                                            value={editarCorrida.destino?.cidade || ""}
                                            onChange={(e) =>
                                                setEditarCorrida((prev) =>
                                                    prev
                                                        ? { ...prev, destino: { ...(prev.destino || {}), cidade: e.target.value } }
                                                        : prev
                                                )
                                            }
                                            disabled={!editDestinoEstado}
                                        >
                                            <option value="">
                                                {editDestinoEstado ? "Selecione a cidade" : "Selecione o estado"}
                                            </option>
                                            {editDestinoCidades.map((cidade) => (
                                                <option key={cidade.id} value={cidade.nome}>
                                                    {cidade.nome}
                                                </option>
                                            ))}
                                        </select>
                                    </div>
                                </div>
                            </div>
                            )}
                        </div>
                        <div className="modal-footer">
                            <button type="button" className="btn btn-secondary" onClick={fecharEditar}>
                                Cancelar
                            </button>
                            <button
                                type="button"
                                className="btn btn-primary"
                                onClick={salvarEdicao}
                                disabled={salvandoEdicao}
                            >
                                {salvandoEdicao ? "Salvando..." : "Salvar"}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
            )}
            {mostrarCarregando && <div className="loading-footer">Carregando</div>}
        </>
    );
}

export default ListarTodosCorridas;
